export function charWidth1000(fontKey: string, code: number): number {
  if (String(fontKey).startsWith('cour')) return 600;
  const tbl = AFM_WIDTHS[fontKey as keyof typeof AFM_WIDTHS] || AFM_WIDTHS.helv;
  const w = tbl && tbl[String(code) as keyof typeof tbl];
  return (typeof w === 'number') ? w : 500;
}

export function textWidthPt(fontKey: string, sizePt: number, str: string): number {
  let sum = 0;
  for (const code of winAnsiBytes(str)) sum += charWidth1000(fontKey, code);
  return sum / 1000 * sizePt;
}
